INSERT INTO tenant_reminders_sent (tenant_id, rule_id, event_id)
VALUES (
  {{ $('Render Template').item.json.tenants_id }},
  {{ $('Render Template').item.json.rule_id }},
  {{ $('Render Template').item.json.event_id || null }}
);

parameters.jsCode:
const item = $input.item.json;

const eventDate = new Date(item.event_datetime);
const event_time = eventDate.toLocaleTimeString('en-US', {
  hour: '2-digit',
  minute: '2-digit',
  timeZone: 'America/Sao_Paulo'
});

const event_date = eventDate.toLocaleDateString('en-US', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  timeZone: 'America/Sao_Paulo'
});

const variables = {
  entity_name: item.entity_name,
  entity_contact: item.entity_contact,
  tenants_id: item.tenants_id,
  event_time,
  event_date,
  ...item.extra_data
};

let message = item.message_template;
for (const [key, value] of Object.entries(variables)) {
  message = message.replaceAll(`{{${key}}}`, value);
}

return {
  event_id: item.event_id,
  rule_id: item.rule_id,
  tenants_id: item.tenants_id,
  channel: item.channel,
  channel_config: item.channel_config,
  message
};

const token = $input.item.json.headers['x-tenant-token'];

if (!token) {
  throw new Error('Missing x-tenant-token header');
}

return {
  token,
  entity_name: $input.item.json.body.entity_name,
  event_datetime: $input.item.json.body.event_datetime,
  extra_data: $input.item.json.body.extra_data || {}
};

const item = $input.item.json;

const channelConfig = JSON.stringify({
  chat_id: item['Chat ID / Contact']
});

return {
  name: item['Client name'],
  channel: item['Channel'],
  channel_config: channelConfig,
  api_token: item['API Token'],
  trigger_type: item['Trigger type'],
  timing_minutes_before: item['Minutes before event'] || null,
  message_template: item['Message template']
};
